      ];

      await store.savePalettes(palettes);
      final loaded = store.loadPalettes();

      expect(loaded.length, 2);
      expect(loaded[0].id, 'pal-1');
      expect(loaded[0].name, 'Fire');
      expect(loaded[0].stops.length, 2);
      expect(loaded[0].stops[0].colorArgb, 0xFFFF0000);
      expect(loaded[0].stops[1].colorArgb, 0xFFFFFF00);

      expect(loaded[1].id, 'pal-2');
      expect(loaded[1].name, 'Ocean');
      expect(loaded[1].stops[0].colorArgb, 0xFF0000FF);
    });

    test('savePalettes and loadPalettes preserves stop positions', () async {
      final store = await PaletteStore.create();

      final palette = const FractalPalette(
        id: 'gradient',
        name: 'Gradient',
        stops: [
          FractalColorStop(position: 0.0, colorArgb: 0xFFFFFFFF),
          FractalColorStop(position: 0.5, colorArgb: 0xFF888888),
          FractalColorStop(position: 1.0, colorArgb: 0xFF000000),
        ],
      );

      await store.savePalettes([palette]);
      final loaded = store.loadPalettes();

      expect(loaded.length, 1);
      expect(loaded[0].stops[1].position, closeTo(0.5, 1e-9));
    });

    test('loadPalettes skips corrupted string-list entries', () async {
      final goodEntry = const FractalPalette(
        id: 'ok',
        name: 'Good',
        stops: [FractalColorStop(position: 0.0, colorArgb: 0xFFFFFFFF)],
      ).toJsonString(pretty: false);

      SharedPreferences.setMockInitialValues({
        'user_palettes_v1': <String>['not valid json {{{{', goodEntry],
      });

      final store = await PaletteStore.create();
      final palettes = store.loadPalettes();

      expect(palettes, hasLength(1));
      expect(palettes.single.id, 'ok');
    });

    test('loadPalettes skips palettes with empty id', () async {
      // Use the List<String> primary path: two serialised palette JSON strings,
      // one with an empty id (should be filtered) and one with a valid id.
      final badEntry = const FractalPalette(
        id: '',
        name: 'Bad',
        stops: [],
      ).toJsonString(pretty: false);
      final goodEntry = const FractalPalette(
        id: 'ok',
        name: 'Good',
        stops: [],
      ).toJsonString(pretty: false);

      SharedPreferences.setMockInitialValues({
        'user_palettes_v1': <String>[badEntry, goodEntry],
      });

      final store = await PaletteStore.create();
      final palettes = store.loadPalettes();
      expect(palettes.length, 1);
      expect(palettes.first.id, 'ok');
    });

    test('savePalettes overwrites previous save', () async {
      final store = await PaletteStore.create();

      final first = [
        const FractalPalette(
          id: 'first',
          name: 'First',
          stops: [FractalColorStop(position: 0.0, colorArgb: 0xFFFF0000)],
        ),
      ];
      final second = [
        const FractalPalette(
          id: 'second',
          name: 'Second',
          stops: [FractalColorStop(position: 0.0, colorArgb: 0xFF00FF00)],
        ),
      ];

      await store.savePalettes(first);
      await store.savePalettes(second);
      final loaded = store.loadPalettes();

      expect(loaded.length, 1);
      expect(loaded.first.id, 'second');
    });

    test('savePalettes with empty list clears palettes', () async {
      final store = await PaletteStore.create();

      final palettes = [
        const FractalPalette(
          id: 'p1',
          name: 'P1',
          stops: [FractalColorStop(position: 0.0, colorArgb: 0xFFFFFFFF)],
        ),
      ];
      await store.savePalettes(palettes);
      await store.savePalettes([]);
      final loaded = store.loadPalettes();

      expect(loaded, isEmpty);
    });
  });
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:vector_math/vector_math.dart';
import 'fractal_view_state.dart';

/// A saved configuration of fractal parameters and view state.
///
/// Presets allow users to save and restore specific fractal configurations,
/// including both the mathematical parameters (iterations, bailout, etc.)
/// and the view state (pan, zoom, rotation).
///
/// Presets can be:
/// - **Built-in**: Included with the app and read-only
/// - **User-created**: Saved by the user with custom thumbnails
///
/// Presets are serializable to JSON for persistent storage.
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final preset = FractalPreset(
///   id: 'my-preset',
///   moduleId: 'mandelbrot',
///   name: 'Deep Zoom',
///   params: {'iterations': 200, 'colorScheme': 2},
///   view: FractalViewState(
///     pan: Vector2(-0.75, 0.1),
///     zoom: 50.0,
///     rotation: Vector3.zero(),
///   ),
///   createdAt: DateTime.now(),
/// );
/// ```
@immutable
class FractalPreset {
  /// Unique identifier for this preset.
  ///
  /// For built-in presets, use a pattern like 'module-name'.
  /// For user presets, typically a UUID.
  final String id;

  /// The fractal module this preset belongs to.
  ///
  /// Must match a [FractalModule.id] in the registry.
  /// Presets are only applicable to their target module.
  final String moduleId;

  /// User-visible name for this preset.
  ///
  /// Should be descriptive and unique within the module's presets.
  final String name;

  /// The fractal parameter values.
  ///
  /// Keys are parameter IDs (e.g., 'iterations', 'colorScheme').
  /// Values are typed according to [FractalParamType].
  final Map<String, Object> params;

  /// The view state (pan, zoom, rotation) for this preset.
  ///
  /// Defines the camera position and orientation when
  /// the preset is applied.
  final FractalViewState view;

  /// When this preset was created.
  ///
  /// Used for sorting and display purposes.
  final DateTime createdAt;

  /// Whether this is a built-in (read-only) preset.
  ///
  /// Built-in presets cannot be edited or deleted by the user.
  final bool isBuiltIn;

  /// Path to the preset's thumbnail image.
  ///
  /// For user presets, this is typically a file path to a
  /// captured PNG. Built-in presets may use asset paths.
  final String? thumbnailPath;

  /// Creates a new [FractalPreset] with the specified configuration.
  const FractalPreset({
    required this.id,
    required this.moduleId,
    required this.name,
    required this.params,
    required this.view,
    required this.createdAt,
    this.isBuiltIn = false,
    this.thumbnailPath,
  });

  /// Creates a copy of this preset with the given fields replaced.
  ///
  /// Useful for creating variations of existing presets. Because `null` means
  /// "keep the existing value" for optional fields, set [clearThumbnailPath]
  /// when a copy must remove an existing thumbnail.
  FractalPreset copyWith({
    String? id,
    String? moduleId,
    String? name,
    Map<String, Object>? params,
    FractalViewState? view,
    DateTime? createdAt,
    bool? isBuiltIn,
    String? thumbnailPath,
    bool clearThumbnailPath = false,
  }) {
    assert(
      !clearThumbnailPath || thumbnailPath == null,
      'thumbnailPath cannot be provided when clearThumbnailPath is true',
    );
    return FractalPreset(
      id: id ?? this.id,
      moduleId: moduleId ?? this.moduleId,
      name: name ?? this.name,
      params: params ?? this.params,
      view: view ?? this.view,
      createdAt: createdAt ?? this.createdAt,
      isBuiltIn: isBuiltIn ?? this.isBuiltIn,
      thumbnailPath:
          clearThumbnailPath ? null : thumbnailPath ?? this.thumbnailPath,
    );
  }

  /// Serializes this preset to a JSON-compatible map.
  ///
  /// Used for persistent storage in SharedPreferences.
  Map<String, Object?> toJson() {
    return {
      'id': id,
      'moduleId': moduleId,
      'name': name,
      'params': params,
      'view': {
        'panX': view.pan.x,
        'panY': view.pan.y,
        'zoom': view.zoom,
        'rotX': view.rotation.x,
        'rotY': view.rotation.y,
        'rotZ': view.rotation.z,
      },
      'createdAt': createdAt.toIso8601String(),
      'isBuiltIn': isBuiltIn,
      'thumbnailPath': thumbnailPath,
    };
  }

  /// Deserializes a preset from a JSON map.
  ///
  /// Throws if required fields are missing.
  static FractalPreset fromJson(Map<String, Object?> json) {
    final view = json['view'] as Map<String, Object?>? ?? {};
    return FractalPreset(
      id: json['id'] as String,
      moduleId: json['moduleId'] as String,
      name: json['name'] as String,
      params: (json['params'] as Map)
          .map((key, value) => MapEntry(key as String, value as Object)),
      view: FractalViewState(
        pan: Vector2(
          (view['panX'] as num? ?? 0).toDouble(),
          (view['panY'] as num? ?? 0).toDouble(),
        ),
        zoom: (view['zoom'] as num? ?? 1).toDouble(),
        rotation: Vector3(
          (view['rotX'] as num? ?? 0).toDouble(),
          (view['rotY'] as num? ?? 0).toDouble(),
          (view['rotZ'] as num? ?? 0).toDouble(),
        ),
      ),
      createdAt: DateTime.tryParse(json['createdAt'] as String? ?? '') ??
          DateTime.now(),
      isBuiltIn: json['isBuiltIn'] as bool? ?? false,
      thumbnailPath: json['thumbnailPath'] as String?,
    );
  }

  /// Parses a list of presets from a JSON string.
  ///
  /// Returns an empty list if [payload] is null or empty.
  /// Skips corrupted entries and continues parsing valid ones.
  /// Used for reading from SharedPreferences.
  static List<FractalPreset> listFromPrefs(String? payload) {
    if (payload == null || payload.isEmpty) {
      return [];
    }
    try {
      final decoded = jsonDecode(payload) as List;
      final presets = <FractalPreset>[];
      for (final item in decoded) {
        try {
          final preset =
              FractalPreset.fromJson((item as Map).cast<String, Object?>());
          presets.add(preset);
        } catch (e) {
          // Skip corrupted preset, continue with others
          if (kDebugMode) debugPrint('Failed to parse preset: $e');
        }
      }
      return presets;
    } catch (e) {
      // Corrupted JSON, return empty list
      if (kDebugMode) debugPrint('Failed to parse presets JSON: $e');
      return [];
    }
  }

  /// Serializes a list of presets to a JSON string.
  ///
  /// Used for writing to SharedPreferences.
  static String listToPrefs(List<FractalPreset> presets) {
    return jsonEncode(presets.map((preset) => preset.toJson()).toList());
  }
}

import 'dart:io';
import 'dart:ui' as ui;
import 'package:flutter/foundation.dart' show kIsWeb;
import 'package:flutter/material.dart';
import 'package:flutter/rendering.dart';
import 'package:flutter/services.dart';
import 'package:image/image.dart' as img;
import 'package:path_provider/path_provider.dart';
import 'package:share_plus/share_plus.dart';
import 'package:flutter_fractals/core/models/export_options.dart';

/// Replayable filename contract for exported files.
///
/// Both caller-supplied prefix and fractal type become path-safe filename
/// segments. Empty or fully-unsafe prefixes fall back to `fractal` so the
/// generated filename is never hidden, absolute, or parent-relative.
class ExportFilenameParts {
  final String prefix;
  final ExportFormat format;
  final String? fractalType;
  final int timestampMillis;

  const ExportFilenameParts({
    required this.prefix,
    required this.format,
    required this.timestampMillis,
    this.fractalType,
  });

  String get safePrefix => _sanitizeSegment(prefix, fallback: 'fractal')!;

  String? get safeFractalType {
    final value = fractalType;
    if (value == null) return null;
    return _sanitizeSegment(value, fallback: null);
  }

  String get filename {
    final type = safeFractalType;
    final typePart = type == null ? '' : '_$type';
    return '$safePrefix${typePart}_$timestampMillis.${format.extension}';
  }

  static String? _sanitizeSegment(String value, {required String? fallback}) {
    final sanitized = value
        .trim()
        .toLowerCase()
        .replaceAll(RegExp(r'[^a-z0-9_\-]+'), '_')
        .replaceAll(RegExp(r'_+'), '_')
        .replaceAll(RegExp(r'^[_\-.]+|[_\-.]+$'), '');
    if (sanitized.isEmpty || sanitized == '.' || sanitized == '..') {
      return fallback;
    }
    return sanitized;
  }
}

class ExportService {
  static const MethodChannel _mediaStoreChannel =
      MethodChannel('fractalforge/media_store');
  const ExportService();

  /// Returns the actual format we can encode today.
  ///
  /// WebP is exposed in the UI, but the current pure-Dart image pipeline
  /// cannot encode WebP yet. We explicitly fall back to PNG so filename,
  /// MIME expectations, and snackbar text stay truthful.
  ExportFormat resolveEffectiveFormat(ExportFormat requested) {
    if (requested == ExportFormat.webp) {
      return ExportFormat.png;
    }
    return requested;
  }

  /// Apply simple legibility overlays for wallpaper usage.
  ///
  /// This keeps the fractal intact while slightly darkening common UI areas.
  Uint8List applyWallpaperStyle(Uint8List pngBytes, {required String style}) {
    try {
      final decoded = img.decodePng(pngBytes);
      if (decoded == null) return pngBytes;

      // style: plain|homeOptimized|lockOptimized
      switch (style) {
        case 'homeOptimized':
          return Uint8List.fromList(
              img.encodePng(_applyBottomGradient(decoded, strength: 0.28)));
        case 'lockOptimized':
          var out = _applyTopGradient(decoded, strength: 0.30);
          out = _applyBottomGradient(out, strength: 0.18);
          return Uint8List.fromList(img.encodePng(out));
        default:
          return pngBytes;
      }
    } catch (_) {
      // If any processing fails, return original bytes.
      return pngBytes;
    }
  }

  img.Image _applyTopGradient(img.Image src, {required double strength}) {
    final out = img.Image.from(src);
    final h = out.height;
    final overlayH = (h * 0.22).round().clamp(1, h);

    for (int y = 0; y < overlayH; y++) {
      final t = 1.0 - (y / overlayH);
      final a = (255 * strength * t).round().clamp(0, 255);
      for (int x = 0; x < out.width; x++) {
        final p = out.getPixel(x, y);
        // Alpha-blend black over pixel (new image package API).
        final r = (p.r.toInt() * (255 - a) / 255).round();
        final g = (p.g.toInt() * (255 - a) / 255).round();
        final b = (p.b.toInt() * (255 - a) / 255).round();
        out.setPixelRgba(x, y, r, g, b, p.a.toInt());
      }
    }

    return out;
  }

  img.Image _applyBottomGradient(img.Image src, {required double strength}) {
    final out = img.Image.from(src);
    final h = out.height;
    final overlayH = (h * 0.28).round().clamp(1, h);

    for (int y = h - overlayH; y < h; y++) {
      final t = (y - (h - overlayH)) / overlayH; // 0..1
      final a = (255 * strength * t).round().clamp(0, 255);
      for (int x = 0; x < out.width; x++) {
        final p = out.getPixel(x, y);
        final r = (p.r.toInt() * (255 - a) / 255).round();
        final g = (p.g.toInt() * (255 - a) / 255).round();
        final b = (p.b.toInt() * (255 - a) / 255).round();
        out.setPixelRgba(x, y, r, g, b, p.a.toInt());
      }
    }

    return out;
  }

  Future<Directory> getExportDirectory() async {
    if (!kIsWeb && Platform.isAndroid) {
      // Avoid runtime storage permission prompts. Use app-scoped external
      // pictures dir when available; otherwise fall back to app documents.
      final dirs = await getExternalStorageDirectories(
        type: StorageDirectory.pictures,
      );
      final baseDir = dirs?.isNotEmpty == true ? dirs!.first : null;
      if (baseDir != null) {
        final exportDir = Directory('${baseDir.path}/FlutterFractals');
        if (!await exportDir.exists()) {
          await exportDir.create(recursive: true);
        }
        return exportDir;
      }
    }
    final dir = await getApplicationDocumentsDirectory();
    final exportDir = Directory('${dir.path}/exports');
    if (!await exportDir.exists()) {
      await exportDir.create(recursive: true);
    }
    return exportDir;
  }

  Future<File> createExportFile({required String filename}) async {
    final dir = await getExportDirectory();
    return File('${dir.path}/$filename');
  }

  /// Capture the widget as raw RGBA bytes at the specified pixel ratio
  Future<Uint8List> capturePng(GlobalKey boundaryKey,
      {double pixelRatio = 2.0}) async {
    Object? lastError;

    for (var attempt = 0; attempt < 3; attempt++) {
      try {
        RenderRepaintBoundary? boundary = boundaryKey.currentContext
            ?.findRenderObject() as RenderRepaintBoundary?;
        if (boundary == null) {
          throw StateError('Boundary not found');
        }

        // Defensive: boundary.toImage() can throw if the layer hasn't painted yet.
        if (boundary.debugNeedsPaint) {
          await WidgetsBinding.instance.endOfFrame;
          boundary = boundaryKey.currentContext?.findRenderObject()
              as RenderRepaintBoundary?;
          if (boundary == null) {
            throw StateError('Boundary not found');
          }
        }

        final image = await boundary.toImage(pixelRatio: pixelRatio);
        try {
          final byteData =
              await image.toByteData(format: ui.ImageByteFormat.png);
          if (byteData == null) {
            throw StateError('Failed to encode PNG');
          }
          return byteData.buffer.asUint8List();
        } finally {
          image.dispose();
        }
      } catch (error) {
        lastError = error;
        if (attempt == 2) {
          rethrow;
        }
        await WidgetsBinding.instance.endOfFrame;
      }
    }

    throw StateError('Failed to capture PNG: $lastError');
  }

  /// Capture with advanced options (format, resolution, metadata)
  Future<Uint8List> captureWithOptions(
    GlobalKey boundaryKey, {
    required ExportOptions options,
    required double screenWidth,
    required double screenHeight,
    void Function(double progress)? onProgress,
  }) async {
    onProgress?.call(0.1);

    // Calculate pixel ratio for target resolution
    final pixelRatio = options.calculatePixelRatio(screenWidth, screenHeight);

    // Capture raw PNG from Flutter
    final rawPng = await capturePng(boundaryKey, pixelRatio: pixelRatio);
    onProgress?.call(0.4);

    // Decode the PNG for processing
    final decodedImage = img.decodePng(rawPng);
    if (decodedImage == null) {
      throw StateError('Failed to decode captured image');
    }
    onProgress?.call(0.5);

    // Resize if needed for target resolution
    final targetDims = options.getTargetDimensions(screenWidth, screenHeight);
    img.Image processedImage;

    if (decodedImage.width != targetDims.$1 ||
        decodedImage.height != targetDims.$2) {
      processedImage = img.copyResize(
        decodedImage,
        width: targetDims.$1,
        height: targetDims.$2,
        interpolation: img.Interpolation.cubic,
      );
    } else {
      processedImage = decodedImage;
    }
    onProgress?.call(0.6);

    // Add watermark if requested
    if (options.addWatermark && options.watermarkText != null) {
      processedImage = _addWatermark(processedImage, options.watermarkText!);
    }
    onProgress?.call(0.7);

    // Embed metadata
    if (options.embedMetadata && options.metadata != null) {
      processedImage = _embedMetadata(processedImage, options.metadata!);
    }
    onProgress?.call(0.8);

    // Encode to target format
    final effectiveFormat = resolveEffectiveFormat(options.format);
    final encoded = _encodeToFormat(processedImage, options, effectiveFormat);
    onProgress?.call(1.0);

    return Uint8List.fromList(encoded);
  }

  img.Image _addWatermark(img.Image image, String text) {
    // Simple text watermark in bottom-right corner
    final fontSize = (image.width / 40).round().clamp(12, 48);
    final padding = fontSize;

    img.drawString(
      image,
      text,
      font: img.arial14,
      x: image.width - (text.length * fontSize ~/ 2) - padding,
      y: image.height - fontSize - padding,
      color: img.ColorRgba8(255, 255, 255, 128),
    );

    return image;
  }

  img.Image _embedMetadata(img.Image image, ExportMetadata metadata) {
    // The image package stores metadata in the image object
    // This will be preserved when encoding to formats that support it
    final exifData = metadata.toExifMap();

    // Add metadata as text chunks (supported in PNG)
    for (final entry in exifData.entries) {
      image.textData ??= {};
      image.textData![entry.key] = entry.value;
    }

    return image;
  }

  Uint8List _encodeToFormat(
    img.Image image,
    ExportOptions options,
    ExportFormat effectiveFormat,
  ) {
    switch (effectiveFormat) {
      case ExportFormat.png:
        return Uint8List.fromList(img.encodePng(image, level: 6));

      case ExportFormat.jpg:
        // JPG doesn't support transparency - always composite onto background
        // transparentBackground option is ignored for JPG (use black background)
        final rgbImage = _removeAlpha(image);
        return Uint8List.fromList(
          img.encodeJpg(rgbImage, quality: options.quality),
        );

      case ExportFormat.webp:
        // Guard rail: resolveEffectiveFormat currently maps WebP->PNG.
        return Uint8List.fromList(img.encodePng(image));
    }
  }

  img.Image _removeAlpha(img.Image image) {
    // Create a new RGB image (no alpha channel) for JPG export
    final result = img.Image(
      width: image.width,
      height: image.height,
      numChannels: 3,
    );

    // Fill with black (space around fractals is typically black/transparent)
    img.fill(result, color: img.ColorRgb8(0, 0, 0));

    // Composite the original image over the black background
    img.compositeImage(result, image);

    return result;
  }

  /// Generate a filename with timestamp and format extension
  String generateFilename({
    String prefix = 'fractal',
    required ExportFormat format,
    String? fractalType,
  }) {
    return ExportFilenameParts(
      prefix: prefix,
      format: format,
      fractalType: fractalType,
      timestampMillis: DateTime.now().millisecondsSinceEpoch,
    ).filename;
  }

  Future<File> saveBytes(Uint8List bytes, {required String filename}) async {
    final file = await createExportFile(filename: filename);
    final written = await file.writeAsBytes(bytes, flush: true);
    await _mirrorImageToMediaStoreIfNeeded(bytes, filename);
    return written;
  }

  Future<void> shareFile(File file, {String? text}) async {
    await Share.shareXFiles([XFile(file.path)], text: text);
  }

  bool _isImageFilename(String filename) {
    final lower = filename.toLowerCase();
    return lower.endsWith('.png') ||
        lower.endsWith('.jpg') ||
        lower.endsWith('.jpeg') ||
        lower.endsWith('.gif') ||
        lower.endsWith('.webp');
  }

  String _mimeTypeForFilename(String filename) {
    final lower = filename.toLowerCase();
    if (lower.endsWith('.jpg') || lower.endsWith('.jpeg')) {
      return 'image/jpeg';
    }
    if (lower.endsWith('.webp')) {
      return 'image/webp';
    }
    if (lower.endsWith('.gif')) {
      return 'image/gif';
    }
    return 'image/png';
  }

  Future<void> _mirrorImageToMediaStoreIfNeeded(
    Uint8List bytes,
    String filename,
  ) async {
    if (kIsWeb || !Platform.isAndroid || !_isImageFilename(filename)) {
      return;
    }

    try {
      await _mediaStoreChannel.invokeMethod<String>('saveImage', {
        'bytes': bytes,
        'filename': filename,
        'mimeType': _mimeTypeForFilename(filename),
      });
    } catch (_) {
      // Best-effort only: keep local export path working even if MediaStore fails.
    }
  }

  /// Export with full options and sharing
  Future<ExportResult> exportWithOptions(
    GlobalKey boundaryKey, {
    required ExportOptions options,
    required double screenWidth,
    required double screenHeight,
    required String fractalType,
    required Map<String, Object> parameters,
    void Function(double progress)? onProgress,
  }) async {
    // Create metadata if embedding is enabled
    final metadata = options.embedMetadata
        ? ExportMetadata(
            fractalType: fractalType,
            parameters: parameters,
            createdAt: DateTime.now(),
          )
        : null;

    final effectiveFormat = resolveEffectiveFormat(options.format);

    final finalOptions = options.copyWith(
      metadata: metadata,
      format: effectiveFormat,
    );

    // Capture and process the image
    final bytes = await captureWithOptions(
      boundaryKey,
      options: finalOptions,
      screenWidth: screenWidth,
      screenHeight: screenHeight,
      onProgress: onProgress,
    );

    // Generate filename and save
    final filename = generateFilename(
      format: effectiveFormat,
      fractalType: fractalType,
    );

    final file = await saveBytes(bytes, filename: filename);
    final targetDims =
        finalOptions.getTargetDimensions(screenWidth, screenHeight);

    return ExportResult(
      file: file,
      format: effectiveFormat,
      width: targetDims.$1,
      height: targetDims.$2,
      fileSize: bytes.length,
    );
  }
}

/// Result of an export operation
class ExportResult {
  final File file;
  final ExportFormat format;
  final int width;
  final int height;
  final int fileSize;

  const ExportResult({
    required this.file,
    required this.format,
    required this.width,
    required this.height,
    required this.fileSize,
  });

  String get formattedSize {
    if (fileSize < 1024) {
      return '$fileSize B';
    } else if (fileSize < 1024 * 1024) {
      return '${(fileSize / 1024).toStringAsFixed(1)} KB';
    } else {
      return '${(fileSize / (1024 * 1024)).toStringAsFixed(1)} MB';
    }
  }

  String get resolution => '$width×$height';
}

