/// Result of a video export operation.
class VideoExportResult {
  final File file;
  final String filePath;
  final int frameCount;
  final Duration duration;
  final int fileSizeBytes;
  final VideoResolution resolution;
  final VideoExportFormat format;

  VideoExportResult({
    required this.file,
    required this.filePath,
    required this.frameCount,
    required this.duration,
    required this.fileSizeBytes,
    required this.resolution,
    required this.format,
  });

  String get formattedSize {
    if (fileSizeBytes < 1024) return '$fileSizeBytes B';
    if (fileSizeBytes < 1024 * 1024)
      return '${(fileSizeBytes / 1024).toStringAsFixed(1)} KB';
    return '${(fileSizeBytes / 1024 / 1024).toStringAsFixed(1)} MB';
  }
}

/// Replayable frame timeline contract for video animations.
class VideoFrameTimeline {
  const VideoFrameTimeline._();

  /// Returns normalized progress in [0, 1] for a frame sequence.
  ///
  /// A single-frame export is defined as the start of the animation. This keeps
  /// frame interpolation deterministic without dividing by zero.
  static double progress({
    required int frameIndex,
    required int totalFrames,
  }) {
    if (totalFrames <= 0) {
      throw ArgumentError('Invalid totalFrames: $totalFrames');
    }
    if (totalFrames == 1) {
      return 0.0;
    }

    return (frameIndex / (totalFrames - 1)).clamp(0.0, 1.0).toDouble();
  }
}

/// Service for exporting fractal animations as video.
class VideoExportService {
  const VideoExportService();

  /// Calculate the view state for a given frame in the animation.
  FractalViewState calculateAnimationFrame({
    required FractalViewState startView,
    required VideoExportOptions options,
    required int frameIndex,
    required int totalFrames,
  }) {
    final t = VideoFrameTimeline.progress(
      frameIndex: frameIndex,
      totalFrames: totalFrames,
    );
    final easedT = options.easing.apply(t);

    switch (options.animationType) {
      case VideoAnimationType.zoomIn:
        final targetZoom = startView.zoom * options.zoomFactor;
        final newZoom = startView.zoom + (targetZoom - startView.zoom) * easedT;
        return startView.copyWith(zoom: newZoom);

      case VideoAnimationType.zoomOut:
        final targetZoom = startView.zoom / options.zoomFactor;
        final newZoom = startView.zoom + (targetZoom - startView.zoom) * easedT;
        return startView.copyWith(zoom: newZoom);

      case VideoAnimationType.rotate:
        final angle = easedT * 2 * math.pi;
        final currentRot = startView.rotation;
        return startView.copyWith(
          rotation: Vector3(currentRot.x, currentRot.y + angle, currentRot.z),
        );

      case VideoAnimationType.pan:
        final angle = easedT * 2 * math.pi;
        final radius = 0.5 / startView.zoom;
        return startView.copyWith(
          pan: Vector2(
            startView.pan.x + radius * math.cos(angle),
            startView.pan.y + radius * math.sin(angle),
          ),
        );

      case VideoAnimationType.parameterSweep:
      case VideoAnimationType.custom:
        return startView;
    }
  }

  /// Calculate parameter values for a parameter sweep animation.
  Map<String, double> calculateParameterFrame({
    required Map<String, Object> startParams,
    required VideoExportOptions options,
    required int frameIndex,
    required int totalFrames,
  }) {
    final sweep = options.parameterSweep;
    if (sweep == null) return {};

    var t = VideoFrameTimeline.progress(
      frameIndex: frameIndex,
      totalFrames: totalFrames,
    );

    if (sweep.pingPong) {
      t = t < 0.5 ? t * 2 : 2 - t * 2;
    }

    final easedT = options.easing.apply(t);
    final value =
        sweep.startValue + (sweep.endValue - sweep.startValue) * easedT;

    return {sweep.parameterId: value};
  }

  /// Generate a unique filename for the export.
  String generateFilename(VideoExportOptions options) {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    return 'fractal_${options.animationType.name}_$timestamp.${options.format.extension}';
  }

  /// Capture a widget as PNG bytes.
  Future<Uint8List> captureWidget(GlobalKey boundaryKey,
      {double pixelRatio = 2.0}) async {
    final boundary = boundaryKey.currentContext?.findRenderObject()
        as RenderRepaintBoundary?;
    if (boundary == null) {
      throw Exception('Could not find render boundary');
    }

    final image = await boundary.toImage(pixelRatio: pixelRatio);
    final byteData = await image.toByteData(format: ui.ImageByteFormat.png);
    if (byteData == null) {
      throw Exception('Could not capture image');
    }

    return byteData.buffer.asUint8List();
  }

  /// Export video with the given options.
  ///
  /// This method captures frames and encodes them. For full video encoding,
  /// use a native plugin or FFmpeg.
  Future<VideoExportResult> exportVideo({
    required VideoExportOptions options,
    required FractalViewState startView,
    required Map<String, Object> startParams,
    required String fractalType,
    required void Function(
            FractalViewState view, Map<String, double>? paramUpdates)
        updateView,
    required Future<Uint8List> Function() captureFrame,
    void Function(double progress, String status)? onProgress,
  }) async {
    if (kIsWeb) throw UnsupportedError('exportVideo is not supported on web');
    final totalFrames = options.totalFrames;

    // Capture and decode frames incrementally to avoid RAM exhaustion
    final decodedFrames = <img.Image>[];

    for (var i = 0; i < totalFrames; i++) {
      // Calculate view for this frame
      final view = calculateAnimationFrame(
        startView: startView,
        options: options,
        frameIndex: i,
        totalFrames: totalFrames,
      );

      // Calculate parameter updates if doing a sweep
      Map<String, double>? paramUpdates;
      if (options.animationType == VideoAnimationType.parameterSweep) {
        paramUpdates = calculateParameterFrame(
          startParams: startParams,
          options: options,
          frameIndex: i,
          totalFrames: totalFrames,
        );
      }

      // Update the fractal
      updateView(view, paramUpdates);

      // Wait for render
      await Future.delayed(const Duration(milliseconds: 16));

      // Capture frame
      final frameBytes = await captureFrame();

      // Decode immediately and release raw bytes
      final decoded = img.decodePng(frameBytes);
      if (decoded == null) {
        throw Exception('Failed to decode frame $i');
      }
      decodedFrames.add(decoded);

      // Report progress
      final progress = (i + 1) / totalFrames;
      onProgress?.call(progress, 'Rendering frame ${i + 1} of $totalFrames');
    }

    // Build animation: first frame + addFrame for rest
    final firstFrame = decodedFrames.first;
    for (var i = 1; i < decodedFrames.length; i++) {
      firstFrame.addFrame(decodedFrames[i]);
    }

    // Encode to GIF
    final bytes = Uint8List.fromList(img.encodeGif(firstFrame));

    // Save to file
    final dir = await getTemporaryDirectory();
    final filename = generateFilename(options);
    final outputPath = '${dir.path}/$filename';
    final outputFile = File(outputPath);
    await outputFile.writeAsBytes(bytes);

    final size = await outputFile.length();

    return VideoExportResult(
      file: outputFile,
      filePath: outputFile.path,
      frameCount: decodedFrames.length,
      duration: options.duration,
      fileSizeBytes: size,
      resolution: options.resolution,
      format: options.format,
    );
  }
}

import 'package:flutter/material.dart';

/// Video export format.
enum VideoExportFormat {
  mp4('MP4', 'mp4'),
  gif('GIF', 'gif');

  final String label;
  final String extension;
  const VideoExportFormat(this.label, this.extension);

  String get displayName => label;
}

/// Animation type for video export.
enum VideoAnimationType {
  zoomIn('Zoom In', Icons.zoom_in),
  zoomOut('Zoom Out', Icons.zoom_out),
  rotate('Rotate', Icons.rotate_right),
  pan('Pan', Icons.pan_tool),
  parameterSweep('Parameter Sweep', Icons.tune),
  custom('Custom', Icons.settings);

  final String label;
  final IconData icon;
  const VideoAnimationType(this.label, this.icon);
}

/// Video resolution presets.
enum VideoResolution {
  sd(480, 'SD (480p)'),
  hd(720, 'HD (720p)'),
  fullHd(1080, 'Full HD (1080p)'),
  qhd(1440, 'QHD (1440p)');

  final int height;
  final String label;
  const VideoResolution(this.height, this.label);

  int get width => (height * 16 / 9).round();
}

/// Frame rate options.
enum VideoFrameRate {
  fps15(15),
  fps24(24),
  fps30(30),
  fps60(60);

  final int fps;
  const VideoFrameRate(this.fps);

  String get label => '$fps fps';
}

/// Replayable frame-count contract for video export durations.
class _VideoFrameCountPolicy {
  static const int minFrames = 1;
  static const int _microsecondsPerSecond = Duration.microsecondsPerSecond;

  const _VideoFrameCountPolicy._();

  /// Converts a duration and frame rate into the number of frames to render.
  ///
  /// Fractional-second durations must not be truncated to zero frames; even a
  /// zero or invalid negative duration remains replayable as a single frame.
  static int fromDurationAndFrameRate({
    required Duration duration,
    required VideoFrameRate frameRate,
  }) {
    final microseconds = duration.inMicroseconds;
    if (microseconds <= 0) return minFrames;

    final scaledFrames = microseconds * frameRate.fps;
    final frameCount =
        (scaledFrames + _microsecondsPerSecond - 1) ~/ _microsecondsPerSecond;
    return frameCount < minFrames ? minFrames : frameCount;
  }
}

/// Quality presets.
enum VideoQualityPreset {
  draft('Draft', 0.5),
  standard('Standard', 0.7),
  high('High', 0.85),
  maximum('Maximum', 1.0);

  final String label;
  final double quality;
  const VideoQualityPreset(this.label, this.quality);
}

/// Animation easing functions.
enum AnimationEasing {
  linear('Linear'),
  easeIn('Ease In'),
  easeOut('Ease Out'),
  easeInOut('Ease In-Out');

  final String label;
  const AnimationEasing(this.label);

  double apply(double t) {
    return switch (this) {
      AnimationEasing.linear => t,
      AnimationEasing.easeIn => t * t,
      AnimationEasing.easeOut => 1 - (1 - t) * (1 - t),
      AnimationEasing.easeInOut =>
        t < 0.5 ? 2 * t * t : 1 - (-2 * t + 2) * (-2 * t + 2) / 2,
    };
  }
}

/// Configuration for parameter sweep animation.
class ParameterSweepConfig {
  final String parameterId;
  final double startValue;
  final double endValue;
  final bool pingPong;

  const ParameterSweepConfig({
    required this.parameterId,
    required this.startValue,
    required this.endValue,
    this.pingPong = false,
  });
}

/// Video export configuration options.
class VideoExportOptions {
  final VideoExportFormat format;
  final VideoAnimationType animationType;
  final VideoResolution resolution;
  final VideoFrameRate frameRate;
  final VideoQualityPreset quality;
  final AnimationEasing easing;
  final Duration duration;
  final double zoomFactor;
  final ParameterSweepConfig? parameterSweep;
  final bool loop;
  final bool includeWatermark;

  const VideoExportOptions({
    this.format = VideoExportFormat.mp4,
    this.animationType = VideoAnimationType.zoomIn,
    this.resolution = VideoResolution.fullHd,
    this.frameRate = VideoFrameRate.fps30,
    this.quality = VideoQualityPreset.high,
    this.easing = AnimationEasing.easeInOut,
    this.duration = const Duration(seconds: 5),
    this.zoomFactor = 10.0,
    this.parameterSweep,
    this.loop = false,
    this.includeWatermark = false,
  });

  VideoExportOptions copyWith({
    VideoExportFormat? format,
    VideoAnimationType? animationType,
    VideoResolution? resolution,
    VideoFrameRate? frameRate,
    VideoQualityPreset? quality,
    AnimationEasing? easing,
    Duration? duration,
    double? zoomFactor,
    ParameterSweepConfig? parameterSweep,
    bool? loop,
    bool? includeWatermark,
  }) {
    return VideoExportOptions(
      format: format ?? this.format,
      animationType: animationType ?? this.animationType,
      resolution: resolution ?? this.resolution,
      frameRate: frameRate ?? this.frameRate,
      quality: quality ?? this.quality,
      easing: easing ?? this.easing,
      duration: duration ?? this.duration,
      zoomFactor: zoomFactor ?? this.zoomFactor,
      parameterSweep: parameterSweep ?? this.parameterSweep,
      loop: loop ?? this.loop,
      includeWatermark: includeWatermark ?? this.includeWatermark,
    );
  }

  int get totalFrames => _VideoFrameCountPolicy.fromDurationAndFrameRate(
        duration: duration,
        frameRate: frameRate,
      );

  /// Estimated file size in MB (rough approximation).
  double get estimatedSizeMb {
    final pixels = resolution.width * resolution.height;
    final bitsPerPixel = format == VideoExportFormat.gif ? 8.0 : 0.15;
    return (pixels * bitsPerPixel * totalFrames) / 8 / 1024 / 1024;
  }
}

/// Preset configurations for quick selection.
class VideoExportPresets {
  static const socialQuick = VideoExportOptions(
    format: VideoExportFormat.gif,
    resolution: VideoResolution.sd,
    frameRate: VideoFrameRate.fps15,
    duration: Duration(seconds: 3),
    quality: VideoQualityPreset.standard,
  );

  static const socialMp4 = VideoExportOptions(
    format: VideoExportFormat.mp4,
    resolution: VideoResolution.hd,
    frameRate: VideoFrameRate.fps30,
    duration: Duration(seconds: 5),
    quality: VideoQualityPreset.high,
  );

  static const highQuality = VideoExportOptions(
    format: VideoExportFormat.mp4,
    resolution: VideoResolution.fullHd,
    frameRate: VideoFrameRate.fps60,
    duration: Duration(seconds: 10),
    quality: VideoQualityPreset.maximum,
  );

  static const gifLoop = VideoExportOptions(
    format: VideoExportFormat.gif,
    resolution: VideoResolution.sd,
    frameRate: VideoFrameRate.fps24,
    duration: Duration(seconds: 4),
    loop: true,
  );
}

